CREATE TABLE IF NOT EXISTS contract_activities (id INT AUTO_INCREMENT PRIMARY KEY,contract_id INT NOT NULL,user_id INT NOT NULL,title VARCHAR(255) NOT NULL,description TEXT,activity_date DATE,status VARCHAR(40) DEFAULT 'draft',user_observation TEXT,admin_comment TEXT,reviewed_by INT,reviewed_at TIMESTAMP NULL,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,INDEX(contract_id),INDEX(user_id),INDEX(status));
CREATE TABLE IF NOT EXISTS contract_activity_files (id INT AUTO_INCREMENT PRIMARY KEY,activity_id INT NOT NULL,contract_id INT NOT NULL,user_id INT NOT NULL,file_name VARCHAR(255),file_path VARCHAR(255),mime_type VARCHAR(160),size_bytes BIGINT,created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,INDEX(activity_id),INDEX(contract_id));
CREATE TABLE IF NOT EXISTS contract_activity_comments (id INT AUTO_INCREMENT PRIMARY KEY,activity_id INT NOT NULL,user_id INT NOT NULL,comment TEXT NOT NULL,visibility VARCHAR(40) DEFAULT 'visible',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,INDEX(activity_id));
CREATE TABLE IF NOT EXISTS system_alerts (id INT AUTO_INCREMENT PRIMARY KEY,user_id INT NULL,contract_id INT NULL,related_type VARCHAR(80),related_id INT,title VARCHAR(220) NOT NULL,message TEXT,severity VARCHAR(40) DEFAULT 'info',status VARCHAR(40) DEFAULT 'unread',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,read_at TIMESTAMP NULL,INDEX(user_id),INDEX(contract_id),INDEX(status));
CREATE TABLE IF NOT EXISTS audit_logs (id INT AUTO_INCREMENT PRIMARY KEY,actor_user_id INT NULL,action VARCHAR(120) NOT NULL,entity_type VARCHAR(80) NOT NULL,entity_id INT NULL,contract_id INT NULL,description TEXT,metadata JSON NULL,ip_address VARCHAR(80),created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,INDEX(actor_user_id),INDEX(entity_type),INDEX(contract_id));
CREATE TABLE IF NOT EXISTS entity_comments (id INT AUTO_INCREMENT PRIMARY KEY,entity_type VARCHAR(80) NOT NULL,entity_id INT NOT NULL,contract_id INT NULL,user_id INT NOT NULL,comment TEXT NOT NULL,visibility VARCHAR(40) DEFAULT 'internal',created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,INDEX(entity_type,entity_id),INDEX(contract_id));
